 1	import type { FC } from 'react';
 2	import { ConsoleTimestamp } from 'src/components/ConsoleTimestamp/ConsoleTimestamp';
 3	import { ModalHOC } from 'src/modules/Providers/modals/ModalHOC/ModalHOC';
 4	import {
 5	  getMigrationVMsStatusCounts,
 6	  getPlanStatus,
 7	} from 'src/plans/details/components/PlanStatus/utils/utils';
 8	import VMStatusIconsRow from 'src/plans/details/components/PlanStatus/VMStatusIconsRow';
 9	import { useForkliftTranslation } from 'src/utils/i18n';
10	
11	import HelpText from '@components/HelpText';
12	import {
13	  MigrationModelGroupVersionKind,
14	  type V1beta1Migration,
15	  type V1beta1Plan,
16	} from '@kubev2v/types';
17	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
18	import { Split } from '@patternfly/react-core';
19	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
20	import { getName, getNamespace, getUID } from '@utils/crds/common/selectors';
21	import { isEmpty } from '@utils/helpers';
22	
23	import { getMigrationStatusLabel } from './utils/utils';
24	
25	type MigrationTableProps = {
26	  migrations: V1beta1Migration[];
27	  plan: V1beta1Plan;
28	};
29	
30	const MigrationsTable: FC<MigrationTableProps> = ({ migrations, plan }) => {
31	  const { t } = useForkliftTranslation();
32	
33	  if (isEmpty(migrations)) {
34	    return (
35	      <HelpText className="pf-v6-u-mt-md">
36	        {t('The plan has not been executed for migration.')}
37	      </HelpText>
38	    );
39	  }
40	
41	  const planStatus = getPlanStatus(plan);
42	  return (
43	    <Table>
44	      <Thead>
45	        <Tr>
46	          <Th width={20}>{t('Migration')}</Th>
47	          <Th width={15}>{t('VMs')}</Th>
48	          <Th width={10}>{t('Started at')}</Th>
49	          <Th width={10}>{t('Completed at')}</Th>
50	        </Tr>
51	      </Thead>
52	      <Tbody>
53	        {migrations.map((migration) => {
54	          const migrationVMs = migration?.status?.vms;
55	          const vmStatuses = getMigrationVMsStatusCounts(
56	            migrationVMs ?? [],
57	            planStatus,
58	            migrationVMs?.length ?? 0,
59	          );
60	
61	          return (
62	            <Tr key={getUID(migration)}>
63	              <Td>
64	                <ResourceLink
65	                  groupVersionKind={MigrationModelGroupVersionKind}
66	                  name={getName(migration)}
67	                  namespace={getNamespace(migration)}
68	                />
69	              </Td>
70	              <Td>
71	                <Split hasGutter>
72	                  {getMigrationStatusLabel(vmStatuses, migrationVMs?.length)}
73	                  <ModalHOC>
74	                    <VMStatusIconsRow statuses={vmStatuses} plan={plan} />
75	                  </ModalHOC>
76	                </Split>
77	              </Td>
78	              <Td>
79	                <ConsoleTimestamp timestamp={migration?.status?.started ?? null} />
80	              </Td>
81	              <Td>
82	                <ConsoleTimestamp timestamp={migration?.status?.completed ?? null} />
83	              </Td>
84	            </Tr>
85	          );
86	        })}
87	      </Tbody>
88	    </Table>
89	  );
90	};
91	
92	export default MigrationsTable;

